namespace BusinessLayer.Dtos.Operations;

public sealed class DashboardMetric { public string Label { get; set; } = string.Empty; public decimal Value { get; set; } public string Format { get; set; } = "number"; }
public sealed class ManagerRevenuePeriod { public string Period { get; set; } = string.Empty; public string Label { get; set; } = string.Empty; public DateTime From { get; set; } public DateTime To { get; set; } public int CompletedVehicles { get; set; } public decimal GrossRevenue { get; set; } public decimal RefundedAmount { get; set; } public decimal NetRevenue { get; set; } }
public sealed class DashboardException { public string Type { get; set; } = string.Empty; public string Severity { get; set; } = "info"; public string Title { get; set; } = string.Empty; public string Detail { get; set; } = string.Empty; public Guid? BranchId { get; set; } public string? BranchName { get; set; } public string ActionPath { get; set; } = string.Empty; public DateTime OccurredAt { get; set; } }
public sealed class ManagerDashboardResponse { public Guid BranchId { get; set; } public string BranchName { get; set; } = string.Empty; public DateTime Date { get; set; } public DateTime GeneratedAt { get; set; } = DateTime.UtcNow; public IReadOnlyList<DashboardMetric> Metrics { get; set; } = []; public IReadOnlyList<ManagerRevenuePeriod> RevenuePeriods { get; set; } = []; public IReadOnlyList<DashboardException> Actions { get; set; } = []; }
public sealed class BranchPerformanceResponse { public Guid BranchId { get; set; } public string BranchName { get; set; } = string.Empty; public int Bookings { get; set; } public decimal CompletionRate { get; set; } public decimal NoShowRate { get; set; } public decimal NetAmount { get; set; } public decimal BayUtilization { get; set; } }
public sealed class AdminDashboardResponse { public DateTime From { get; set; } public DateTime To { get; set; } public DateTime GeneratedAt { get; set; } = DateTime.UtcNow; public IReadOnlyList<DashboardMetric> Metrics { get; set; } = []; public IReadOnlyList<DashboardException> Exceptions { get; set; } = []; public IReadOnlyList<BranchPerformanceResponse> Branches { get; set; } = []; }
